module top_module(num, dig, obf_code);input [2:0]			num;		
	input [39:0]		dig;
	output reg [4:0]	obf_code;		

	always @(num) begin
        case(num)
            3'd0: obf_code = dig[4:0];
            3'd1: obf_code = dig[9:5];
            3'd2: obf_code = dig[14:10];
            3'd3: obf_code = dig[19:15];
            3'd4: obf_code = dig[24:20];
            3'd5: obf_code = dig[29:25];
            3'd6: obf_code = dig[34:30];
            3'd7: obf_code = dig[39:35];
            default: obf_code = 5'b00000;
        endcase
    end

endmodule
